import React, { useState, useEffect } from 'react';
import { Container } from 'react-bootstrap';
import './CustomParallax.css';

const CustomParallax = ({ elements }) => {
  const [scrollPercentage, setScrollPercentage] = useState(0);

  useEffect(() => {
    const handleScroll = () => {
      const scrolled = window.pageYOffset;
      const windowHeight = window.innerHeight;
      const documentHeight = document.body.clientHeight;
      const scrollPercentage = (scrolled / (documentHeight - windowHeight)) * 100;
      setScrollPercentage(scrollPercentage);

      elements.forEach((element, index) => {
        const mount = document.querySelector(`#scroll${index + 1}`);
        if (mount) {
          const speed = element.speed;
          const transformValue = scrollPercentage * speed;
          mount.style.transform = `translateX(${transformValue}px)`;
        }
      });
    };

    window.addEventListener('scroll', handleScroll);

    return () => {
      window.removeEventListener('scroll', handleScroll);
    };
  }, [elements, scrollPercentage]);

  return (
    <div className="section_parallax">
      <Container>
        {elements.map((element, index) => (
          <div
            key={index}
            id={`scroll${index + 1}`}
            className="parallax-element"
            style={{ height: element.height, top: element.top, right: element.right, left: element.left }}
          ></div>
        ))}
      </Container>
    </div>
  );
};

export default CustomParallax;
